on_insert.sql:
DO $$ DECLARE v_counter integer; v_code varchar(2); v_odg_no varchar(2); v_resgrp_cd varchar(2); v_reslin_cd varchar(2); v_status_cd varchar(1); v_dba_cd integer; v_portf_proj_cd varchar(1); v_description varchar(500); v_reslin_desc varchar(60); v_theme_desc_length integer; v_d_registrat_date date; v_d_ins_date date; v_future_registrat date; v_valid_to date; v_userid varchar(30); v_is_admin_cnt integer := 0; v_sec_mol_cnt integer := 0; v_molecule_id varchar(5) := null; v_molecule_rg_no varchar(20) := null; v_molec_in_lic_prtnr varchar(15) := null; v_new_rg_no v_theme_molecules.rg_no%type; v_comparator_ind v_theme_molecules.comparator_ind%type; v_theme_desc_proposal mdm_v_themes_mtn.theme_desc_proposal%type; v_short_name varchar(30); v_evolved_nmp_cnt integer; v_trademark_no v_themes.trademark_no%type; v_molecule_type_id v_molecule_types.molecule_type_id%type; v_pharmacological_type_id v_pharmacological_types.pharmacological_type_id%type; c_molecule_type_id constant v_molecule_types.molecule_type_id%type := 99; c_pharmacological_type_id constant v_pharmacological_types.pharmacological_type_id%type := 19; v_userid varchar(30);BEGIN
select COALESCE(txo_security.get_userid, current_user) into v_userid
from dual;
select count(*)
 into v_is_admin_cnt
from txo_users_roles_map
where role_id in (315)
and userid = v_userid;
SELECT new_rg_no INTO v_new_rg_no
FROM (
SELECT rn AS new_rg_no
FROM generate_series(6000, 6999) AS rn EXCEPT
SELECT rg_no::INTEGER
FROM gmd.v_theme_molecules_mrhub) AS free_rg LIMIT 1;
if (:new_in_prep_ind = 'Y')
then if (:new_portf_proj_cd <> 'Y')
then RAISE
EXCEPTION 'MDM_V_THEMES_IOF: In-prep theme must be portfolio project';
 end if;
if (:new_status_desc <> 'CLOSED'
and v_is_admin_cnt = 0)
then RAISE
EXCEPTION 'MDM_V_THEMES_IOF: In-prep status validation failed';
 end if;
if (:new_molecule_id is null)
then txo_util$set_warning('No Molecule assigned to In-Prep Theme ' || :new_theme_no || '!');
 end if;
 end if;
if (:new_molecule_id is not null)
then begin
select rg_no
 ,m.comparator_ind
 into v_molecule_rg_no
 ,v_comparator_ind
from v_theme_molecules m
where molecule_id = :new_molecule_id
and m.valid_ind = 'Y';
exception when no_data_found
then RAISE
EXCEPTION 'MDM_V_THEMES_IOF: This is not a valid Molecule ID';
 end;
if (v_molecule_rg_no is null)
then if (v_comparator_ind = 'Y')
then null;
else update v_theme_molecules
 set rg_no = v_new_rg_no
where molecule_id = :new_molecule_id;
 end if;
 end if;
 end if;
 v_odg_no := SUBSTRING(:new_reslin_desc_concat
FROM 1 FOR 2);
 v_resgrp_cd := SUBSTRING(:new_reslin_desc_concat
FROM 4 FOR 2);
 v_reslin_cd := SUBSTRING(:new_reslin_desc_concat
FROM 7 FOR 2);
 v_reslin_desc := SUBSTRING(:new_reslin_desc_concat
FROM 12 FOR LENGTH(:new_reslin_desc_concat));
if (:new_status_desc is not null)
then select status_cd
 into v_status_cd
from mdm_v_theme_status
where state_desc = :new_status_desc;
else v_status_cd := null;
 end if;
if (:new_dba_desc_concat is not null)
then select dba_cd
 into v_dba_cd
from mdm_v_disease_biology_areas
where dba_short_desc || ' - ' || dba_desc = :new_dba_desc_concat;
else v_dba_cd := null;
 end if;
 v_molec_in_lic_prtnr := gmd_util_themes$get_molec_in_lic_prtnr(:new_molecule_id);
if (:new_official_ind = 'N')
THEN v_trademark_no := :new_trademark_no;
ELSE v_trademark_no := :old_trademark_no;
 END IF;
 v_theme_desc_proposal := gmd_util_themes$get_theme_short_name(p_theme_no_portf => :new_theme_no
 ,p_molecule_id_portf => :new_molecule_id
 ,p_prod_short_cd_portf => :new_prod_short_cd
 ,p_odg_no_port => v_odg_no
 ,p_resgrp_cd_port => v_resgrp_cd
 ,p_reslin_cd_port => v_reslin_cd
 ,p_line_ext_info_port => :new_line_ext_info
 ,p_in_lic_prtnr_portf => null
 ,p_trademark_no_portf => v_trademark_no
 ,p_trunc_desc_length => 'N');
if (:new_manual_short_desc is null
and LENGTH(v_theme_desc_proposal) > 30)
then RAISE
EXCEPTION 'MDM_V_THEMES_IOF: The automatically generated Short Description Proposal is too long';
 end if;
 v_short_name := coalesce(:new_manual_short_desc, v_theme_desc_proposal);
if (:new_in_prep_ind = 'N'
and v_is_admin_cnt = 0)
then RAISE
EXCEPTION 'MDM_V_THEMES_IOF: Admin access required for this operation';
 end if;
 v_molecule_id := :new_molecule_id;
if (:new_portf_proj_cd = 'Y'
and :new_molecule_id is null)
then if (COALESCE(:new_manual_short_desc, :new_theme_desc_proposal) is null)
then RAISE
EXCEPTION 'MDM_V_THEMES_IOF: Portfolio project molecule creation error';
else insert into mdm_v_theme_molecules_mtn(molecule_desc
 ,valid_ind
 ,rg_no
 ,cancer_immunotherapy_ind
 ,molecule_type_id
 ,pharmacological_type_id)
 values (COALESCE(:new_manual_short_desc, :new_theme_desc_proposal)
 ,'Y'
 ,v_new_rg_no
 ,'N'
 ,c_molecule_type_id
 ,c_pharmacological_type_id);
select molecule_id
 into v_molecule_id
from v_theme_molecules
where molecule_desc = COALESCE(:new_manual_short_desc, :new_theme_desc_proposal)
and valid_ind = 'Y'
and rg_no = v_new_rg_no
and cancer_immunotherapy_ind = 'N'
and molecule_type_id = c_molecule_type_id
and pharmacological_type_id = c_pharmacological_type_id;
insert into theme_molecule_map tmmap(tmmap.theme_no
 ,tmmap.molecule_id
 ,tmmap.molecule_seq_no
 ,tmmap.valid_ind)
 values (:new_theme_no, v_molecule_id, 1, 'Y'); 
 end if;
 end if;
 case LENGTH(:new_theme_no)
 when 4
then if (SUBSTRING(:new_theme_no
FROM 1 FOR 1) not between 0
and 9
or SUBSTRING(:new_theme_no
FROM 2 FOR 1) not between 0
and 9
or SUBSTRING(:new_theme_no
FROM 3 FOR 1) not between 0
and 9
or SUBSTRING(:new_theme_no
FROM 4 FOR 1) not between 0
and 9)
then RAISE
EXCEPTION 'MDM_V_THEMES_IOF: This is not a valid Theme No';
 end if;
 when 5
then if (SUBSTRING(:new_theme_no
FROM 1 FOR 1) not between 0
and 9
or SUBSTRING(:new_theme_no
FROM 2 FOR 1) not between 0
and 9
or SUBSTRING(:new_theme_no
FROM 3 FOR 1) not between 0
and 9
or SUBSTRING(:new_theme_no
FROM 4 FOR 1) not between 0
and 9
or SUBSTRING(:new_theme_no
FROM 5 FOR 1) !~ \'^[0-9]$\')
then RAISE
EXCEPTION 'MDM_V_THEMES_IOF: This is not a valid Theme No';
 end if;
else RAISE
EXCEPTION 'MDM_V_THEMES_IOF: This is not a valid Theme No';
 end case;
 v_counter := null;
select count(t.theme_no)
 into v_counter
from (select theme_no
from v_themes
 union all
select theme_no
from gmd.themes_archive) t
where t.theme_no = :new_theme_no;
if (v_counter > 0)
then RAISE
EXCEPTION 'MDM_V_THEMES_IOF: This Theme No already exists';
 end if;
 v_counter := null;
 v_d_registrat_date := CURRENT_DATE;
if (:new_official_ind = 'N')
then RAISE
EXCEPTION 'MDM_V_THEMES_IOF: New Themes can only be inserted by Official Changes';
 end if;
if (UPPER(:new_portf_proj_cd) = 'N')
then if (:new_theme_desc is null
or LENGTH(:new_theme_desc) = 0)
then RAISE
EXCEPTION 'MDM_V_THEMES_IOF:
If Pharma Rx Portfolio Project is set to "No",
then the Theme Description must be filled';
 end if;
 end if;
if (UPPER(:new_portf_proj_cd) = 'Y')
then v_description := gmd.gmd_util_themes$get_theme_desc_portfolio(p_theme_no_portf => null
 ,p_molecule_id_portf => v_molecule_id
 ,p_prod_short_cd_portf => :new_prod_short_cd
 ,p_odg_no_port => v_odg_no
 ,p_resgrp_cd_port => v_resgrp_cd
 ,p_reslin_cd_port => v_reslin_cd
 ,p_line_ext_info_port => :new_line_ext_info
 ,p_in_lic_prtnr_portf => v_molec_in_lic_prtnr
 ,p_trademark_no_portf => :new_trademark_no
 ,p_short_name_portf => :new_short_name
 ,p_trunc_desc_length => 'N');
if (LENGTH(v_description) > 90)
then RAISE
EXCEPTION 'MDM_V_THEMES_IOF: The automatically generated Theme Description is too long';
 end if;
 v_description := TRIM(v_description);
 v_portf_proj_cd := 'Y';
else v_description := :new_theme_desc;
 v_portf_proj_cd := 'N';
 end if; 
 v_counter := null;
select count(t.theme_no)
 into v_counter
from v_themes t
where t.theme_desc = v_description;
if (v_counter > 0)
then RAISE
EXCEPTION 'MDM_V_THEMES_IOF: This Theme Description already exists';
 end if;
 v_counter := null;
 v_valid_to := TO_DATE('09.09.9999', 'DD.MM.YYYY');
 v_short_name := COALESCE(:new_manual_short_desc, SUBSTRING(v_description
FROM 1 FOR 30));
insert into gmd.themes(theme_no
 ,registrat_date
 ,odg_no
 ,resgrp_cd
 ,reslin_cd
 ,theme_desc
 ,short_name
 ,status_cd
 ,dba_cd
 ,in_prep_ind
 ,prod_short_cd
 ,trademark_no
 ,bio_activity
 ,applicant
 ,contact
 ,registrar
 ,line_ext_info
 ,portf_proj_cd
 ,co_dev_prtnr
 ,technology_prtnr
 ,official_ind
 ,co_mar_prtnr
 ,valid_to
 ,portf_da_group_id
 ,manual_short_desc)
 values (:new_theme_no
 ,v_d_registrat_date
 ,v_odg_no
 ,v_resgrp_cd
 ,v_reslin_cd
 ,v_description
 ,v_short_name
 ,v_status_cd
 ,v_dba_cd
 ,:new_in_prep_ind
 ,:new_prod_short_cd
 ,:new_trademark_no
 ,:new_bio_activity
 ,:new_applicant
 ,:new_contact
 ,:ins_user
 ,:new_line_ext_info
 ,v_portf_proj_cd
 ,:new_co_dev_prtnr
 ,:new_technology_prtnr
 ,:new_official_ind
 ,:new_co_mar_prtnr
 ,v_valid_to
 ,:new_portf_da_group_id
 ,:new_manual_short_desc);
if (:old_molecule_id is null
and :new_molecule_id is not null)
then insert into mdm_v_theme_molecule_map_mtn a(a.theme_no
 ,a.molecule_id
 ,a.molecule_seq_no
 ,a.valid_ind)
 values (:new_theme_no, v_molecule_id, 1, 'Y'); 
 end if; END $$;

on_update.sql:
DO $$ DECLARE v_counter integer; v_code varchar(2); v_odg_no varchar(2); v_resgrp_cd varchar(2); v_reslin_cd varchar(2); v_status_cd varchar(1); v_dba_cd integer; v_portf_proj_cd varchar(1); v_description varchar(500); v_reslin_desc varchar(60); v_theme_desc_length integer; v_d_registrat_date date; v_d_ins_date date; v_future_registrat date; v_valid_to date; v_userid varchar(30); v_is_admin_cnt integer := 0; v_sec_mol_cnt integer := 0; v_molecule_id varchar(5) := null; v_molecule_rg_no varchar(20) := null; v_molec_in_lic_prtnr varchar(15) := null; v_new_rg_no v_theme_molecules.rg_no%type; v_comparator_ind v_theme_molecules.comparator_ind%type; v_theme_desc_proposal mdm_v_themes_mtn.theme_desc_proposal%type; v_short_name varchar(30); v_evolved_nmp_cnt integer; v_trademark_no v_themes.trademark_no%type; v_molecule_type_id v_molecule_types.molecule_type_id%type; v_pharmacological_type_id v_pharmacological_types.pharmacological_type_id%type; c_molecule_type_id constant v_molecule_types.molecule_type_id%type := 99; c_pharmacological_type_id constant v_pharmacological_types.pharmacological_type_id%type := 19; v_userid varchar(30);BEGIN
select COALESCE(txo_security.get_userid, current_user) into v_userid
from dual;
select count(*)
 into v_is_admin_cnt
from txo_users_roles_map
where role_id in (315)
and userid = v_userid;
SELECT new_rg_no INTO v_new_rg_no
FROM (
SELECT rn AS new_rg_no
FROM generate_series(6000, 6999) AS rn EXCEPT
SELECT rg_no::INTEGER
FROM gmd.v_theme_molecules_mrhub) AS free_rg LIMIT 1;
if (:new_in_prep_ind = 'Y')
then if (:new_portf_proj_cd <> 'Y')
then RAISE
EXCEPTION 'MDM_V_THEMES_IOF: In-prep theme must be portfolio project';
 end if;
if (:new_status_desc <> 'CLOSED'
and v_is_admin_cnt = 0)
then RAISE
EXCEPTION 'MDM_V_THEMES_IOF: In-prep status validation failed';
 end if;
if (:new_molecule_id is null)
then txo_util$set_warning('No Molecule assigned to In-Prep Theme ' || :new_theme_no || '!');
 end if;
 end if;
if (:new_molecule_id is not null)
then begin
select rg_no
 ,m.comparator_ind
 into v_molecule_rg_no
 ,v_comparator_ind
from v_theme_molecules m
where molecule_id = :new_molecule_id
and m.valid_ind = 'Y';
exception when no_data_found
then RAISE
EXCEPTION 'MDM_V_THEMES_IOF: This is not a valid Molecule ID';
 end;
if (v_molecule_rg_no is null)
then if (v_comparator_ind = 'Y')
then null;
else update v_theme_molecules
 set rg_no = v_new_rg_no
where molecule_id = :new_molecule_id;
 end if;
 end if;
 end if;
 v_odg_no := SUBSTRING(:new_reslin_desc_concat
FROM 1 FOR 2);
 v_resgrp_cd := SUBSTRING(:new_reslin_desc_concat
FROM 4 FOR 2);
 v_reslin_cd := SUBSTRING(:new_reslin_desc_concat
FROM 7 FOR 2);
 v_reslin_desc := SUBSTRING(:new_reslin_desc_concat
FROM 12 FOR LENGTH(:new_reslin_desc_concat));
if (:new_status_desc is not null)
then select status_cd
 into v_status_cd
from mdm_v_theme_status
where state_desc = :new_status_desc;
else v_status_cd := null;
 end if;
if (:new_dba_desc_concat is not null)
then select dba_cd
 into v_dba_cd
from mdm_v_disease_biology_areas
where dba_short_desc || ' - ' || dba_desc = :new_dba_desc_concat;
else v_dba_cd := null;
 end if;
 v_molec_in_lic_prtnr := gmd_util_themes$get_molec_in_lic_prtnr(:new_molecule_id);
if (:new_official_ind = 'N')
THEN v_trademark_no := :new_trademark_no;
ELSE v_trademark_no := :old_trademark_no;
 END IF;
 v_theme_desc_proposal := gmd_util_themes$get_theme_short_name(p_theme_no_portf => :new_theme_no
 ,p_molecule_id_portf => :new_molecule_id
 ,p_prod_short_cd_portf => :new_prod_short_cd
 ,p_odg_no_port => v_odg_no
 ,p_resgrp_cd_port => v_resgrp_cd
 ,p_reslin_cd_port => v_reslin_cd
 ,p_line_ext_info_port => :new_line_ext_info
 ,p_in_lic_prtnr_portf => null
 ,p_trademark_no_portf => v_trademark_no
 ,p_trunc_desc_length => 'N');
if (:new_manual_short_desc is null
and LENGTH(v_theme_desc_proposal) > 30)
then RAISE
EXCEPTION 'MDM_V_THEMES_IOF: The automatically generated Short Description Proposal is too long';
 end if;
 v_short_name := coalesce(:new_manual_short_desc, v_theme_desc_proposal);
if (:old_in_prep_ind = 'N'
 or(:old_in_prep_ind = 'Y'
 and:new_in_prep_ind = 'N'))
and v_is_admin_cnt = 0
then RAISE
EXCEPTION 'MDM_V_THEMES_IOF: Admin access required for this operation';
 end if;
if (:new_theme_no <> :old_theme_no)
then RAISE
EXCEPTION 'MDM_V_THEMES_IOF: Theme No cannot be updated';
 end if;
if (:new_official_ind = 'N')
then v_d_registrat_date := TO_DATE(:old_registrat_date, 'dd-mm-yyyy');
else v_d_registrat_date := CURRENT_DATE;
 end if;
if (UPPER(:new_portf_proj_cd) = 'Y' 
 and(v_status_cd <> 'C' 
 or:new_in_prep_ind = 'Y'))
