 ,official_ind = :new_official_ind
 ,co_mar_prtnr = :new_co_mar_prtnr
 ,portf_da_group_id = :new_portf_da_group_id
 ,manual_short_desc = :new_manual_short_desc
where theme_no = :new_theme_no
and TO_DATE(registrat_date, 'DD-MM-YYYY') = v_d_registrat_date;
else v_counter := null;
select count(*)
 into v_counter
from v_themes t
where DATE(t.registrat_date) = DATE(CURRENT_DATE)
and t.theme_no = :new_theme_no;
if (v_counter > 0)
then RAISE
EXCEPTION 'MDM_V_THEMES_IOF: Official Change for this Theme No
and Day already exists';
 end if;
 v_counter := null;
update gmd.themes
 set odg_no = v_odg_no
 ,resgrp_cd = v_resgrp_cd
 ,reslin_cd = v_reslin_cd
 ,theme_desc = v_description
 ,short_name = v_short_name
 ,status_cd = v_status_cd
 ,dba_cd = v_dba_cd
 ,in_prep_ind = :new_in_prep_ind
