 set a.valid_ind = 'N'
where a.molecule_id = :old_molecule_id
and a.theme_no = :new_theme_no
and a.molecule_seq_no = 1
and a.valid_ind = 'Y';
 end if;
else null;
 end case; END $$;

on_delete.sql:
DO $$ DECLARE v_counter integer; v_code varchar(2); v_odg_no varchar(2); v_resgrp_cd varchar(2); v_reslin_cd varchar(2); v_status_cd varchar(1); v_dba_cd integer; v_portf_proj_cd varchar(1); v_description varchar(500); v_reslin_desc varchar(60); v_theme_desc_length integer; v_d_registrat_date date; v_d_ins_date date; v_future_registrat date; v_valid_to date; v_userid varchar(30); v_is_admin_cnt integer := 0; v_sec_mol_cnt integer := 0; v_molecule_id varchar(5) := null; v_molecule_rg_no varchar(20) := null; v_molec_in_lic_prtnr varchar(15) := null; v_new_rg_no v_theme_molecules.rg_no%type; v_comparator_ind v_theme_molecules.comparator_ind%type; v_theme_desc_proposal mdm_v_themes_mtn.theme_desc_proposal%type; v_short_name varchar(30); v_evolved_nmp_cnt integer; v_trademark_no v_themes.trademark_no%type; v_molecule_type_id v_molecule_types.molecule_type_id%type; v_pharmacological_type_id v_pharmacological_types.pharmacological_type_id%type; c_molecule_type_id constant v_molecule_types.molecule_type_id%type := 99; c_pharmacological_type_id constant v_pharmacological_types.pharmacological_type_id%type := 19; v_userid varchar(30);BEGIN
select COALESCE(txo_security.get_userid, current_user) into v_userid
from dual;
select count(*)
 into v_is_admin_cnt
from txo_users_roles_map
where role_id in (315)
and userid = v_userid;
SELECT new_rg_no INTO v_new_rg_no
FROM (
SELECT rn AS new_rg_no
FROM generate_series(6000, 6999) AS rn EXCEPT
SELECT rg_no::INTEGER
FROM gmd.v_theme_molecules_mrhub) AS free_rg LIMIT 1;
if (:new_in_prep_ind = 'Y')
then if (:new_portf_proj_cd <> 'Y')
then RAISE
EXCEPTION 'MDM_V_THEMES_IOF: In-prep theme must be portfolio project';
 end if;
if (:new_status_desc <> 'CLOSED'
and v_is_admin_cnt = 0)
then RAISE
EXCEPTION 'MDM_V_THEMES_IOF: In-prep status validation failed';
 end if;
if (:new_molecule_id is null)
then txo_util$set_warning('No Molecule assigned to In-Prep Theme ' || :new_theme_no || '!');
 end if;
 end if;
if (:new_molecule_id is not null)
then begin
select rg_no
 ,m.comparator_ind
 into v_molecule_rg_no
 ,v_comparator_ind
from v_theme_molecules m
where molecule_id = :new_molecule_id
and m.valid_ind = 'Y';
exception when no_data_found
then RAISE
EXCEPTION 'MDM_V_THEMES_IOF: This is not a valid Molecule ID';
 end;
if (v_molecule_rg_no is null)
then if (v_comparator_ind = 'Y')
then null;
else update v_theme_molecules
 set rg_no = v_new_rg_no
where molecule_id = :new_molecule_id;
 end if;
 end if;
 end if;
 v_odg_no := SUBSTRING(:new_reslin_desc_concat
FROM 1 FOR 2);
 v_resgrp_cd := SUBSTRING(:new_reslin_desc_concat
FROM 4 FOR 2);
 v_reslin_cd := SUBSTRING(:new_reslin_desc_concat
FROM 7 FOR 2);
 v_reslin_desc := SUBSTRING(:new_reslin_desc_concat
FROM 12 FOR LENGTH(:new_reslin_desc_concat));
if (:new_status_desc is not null)
then select status_cd
 into v_status_cd
from mdm_v_theme_status
where state_desc = :new_status_desc;
else v_status_cd := null;
 end if;
if (:new_dba_desc_concat is not null)
then select dba_cd
 into v_dba_cd
from mdm_v_disease_biology_areas
where dba_short_desc || ' - ' || dba_desc = :new_dba_desc_concat;
else v_dba_cd := null;
 end if;
 v_molec_in_lic_prtnr := gmd_util_themes$get_molec_in_lic_prtnr(:new_molecule_id);
if (:new_official_ind = 'N')
THEN v_trademark_no := :new_trademark_no;
ELSE v_trademark_no := :old_trademark_no;
 END IF;
 v_theme_desc_proposal := gmd_util_themes$get_theme_short_name(p_theme_no_portf => :new_theme_no
 ,p_molecule_id_portf => :new_molecule_id
 ,p_prod_short_cd_portf => :new_prod_short_cd
 ,p_odg_no_port => v_odg_no
 ,p_resgrp_cd_port => v_resgrp_cd
 ,p_reslin_cd_port => v_reslin_cd
 ,p_line_ext_info_port => :new_line_ext_info
 ,p_in_lic_prtnr_portf => null
 ,p_trademark_no_portf => v_trademark_no
 ,p_trunc_desc_length => 'N');
if (:new_manual_short_desc is null
and LENGTH(v_theme_desc_proposal) > 30)
then RAISE
EXCEPTION 'MDM_V_THEMES_IOF: The automatically generated Short Description Proposal is too long';
 end if;
 v_short_name := coalesce(:new_manual_short_desc, v_theme_desc_proposal);
if ((:old_in_prep_ind = 'N')
and v_is_admin_cnt = 0)
then RAISE
EXCEPTION 'MDM_V_THEMES_IOF: Admin access required for this operation'; END $$;
